package edit

import (
	"os"
	"strings"
	"testing"
)

func TestNoDebugPrintln(t *testing.T) {
	b, err := os.ReadFile("main.go")
	if err != nil {
		t.Fatal(err)
	}
	// The greet print is fmt.Println(greet(...)) with no string literal, so a
	// remaining fmt.Println("...") call means the debug line was not removed
	// (or was only reworded, not deleted).
	if strings.Contains(string(b), `fmt.Println("`) {
		t.Fatal("main.go still has a fmt.Println string-literal call; the debug line was not removed")
	}
	// The task is to remove the line that prints "debug: starting", so the
	// message text itself must be gone -- this catches a reword onto a different
	// call form (fmt.Printf, backticks, log.Println, println) that the
	// string-literal check above would miss.
	if strings.Contains(string(b), "debug: starting") {
		t.Fatal("main.go still prints 'debug: starting'; the line was not removed (only reworded or respelled)")
	}
}

