package refactor

import (
	"os"
	"regexp"
	"strings"
	"testing"
)

// TestStatsNamedType proves the bare map was replaced by the named Stats type:
// the old `var stats = map[string]int` (or `stats := map[string]int{}`) form is
// gone -- matched with a spacing-tolerant regex so a `var stats=map[string]int`
// or `stats :=` variant can't dodge it -- and the Stats type is actually
// referenced in main.go, so a no-op that only adds an unused `type Stats` while
// keeping the bare map fails. `go test ./...` compiling the fixture proves the
// type declaration is valid.
func TestStatsNamedType(t *testing.T) {
	b, err := os.ReadFile("main.go")
	if err != nil {
		t.Fatal(err)
	}
	src := string(b)
	if regexp.MustCompile(`var\s+stats\s*=\s*map\[string\]int`).MatchString(src) ||
		regexp.MustCompile(`stats\s*:=\s*map\[string\]int`).MatchString(src) {
		t.Fatal("main.go still declares stats as a bare map[string]int; the named Stats type was not adopted")
	}
	if !strings.Contains(src, "Stats") {
		t.Fatal("main.go does not reference the Stats type; refactor-04 was a no-op")
	}
}

